class BookMyShow {
public:
    BookMyShow(int n, int m) {

    }

    vector<int> gather(int k, int maxRow) {
        for (int i = 0; i <= maxRow; ++i) {
            for (int j = 0; j <= m - k; ++j) {
                bool valid = true;
                for (int l = 0; l < k; ++l) {
                    if (j + l >= m) {
                        valid = false;
                        break;
                    }
                }
                if (valid) {
                    return {i, j};
                }
            }
        }
        return {};
    }

    bool scatter(int k, int maxRow) {
        vector<bool> seats(n * m, false);
        for (int i = 0; i <= maxRow; ++i) {
            for (int j = 0; j < m; ++j) {
                if (!seats[i * m + j] && k > 0) {
                    seats[i * m + j] = true;
                    k--;
                }
            }
        }
        return k == 0;
    }
};
